var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"네! 저 할게요!","JPN":"はい！　私、やります！","ENG":"Okay! I'll do it!","TWN":"好的！讓我來吧！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"여기에 도장만 찍으면, 이제 저도 어엿한 어른이 되는 거군요.","JPN":"ここにハンコを押すと、もう私も立派な大人になるのですね。","ENG":"So if I sign here, I'll officially become an adult.","TWN":"只要在這裡蓋章，我也就正式成為大人囉。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"네? 그거랑 다르다고요? 그치만 서윤 언니가 계약은 어른들만 하는 거랬는데?","JPN":"えっ？　それとは違うんですか？　でもシズカ姉さんが契約ができるのは大人だけだって言ってましたよ？","ENG":"Huh? It's not like that? But Sis said only adults sign contracts!","TWN":"嗯？不一樣嗎？可是徐芸姊姊說契約是大人才會做的欸。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"앗, 갑자기 그렇게 다시 가져가는 게 어딨어요! 저도 하고 싶단 말이예요! 계약!","JPN":"あっ、いきなり回収するのはズルいです！　私もやりたいんです！　契約！","ENG":"Wait, you can't just take it away like that! I want to sign it too! A contract!","TWN":"哎呀，怎麼突然就這樣拿回去呢！我也想要！契約！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"심부름 안 까먹고 잘 할게요. 놀다가 컴퓨터 부수지도 않을게요. 관리자 씨 초상화도 매일매일 그려 줄게요!","JPN":"おつかい、忘れないでちゃんとやります。遊ぶときパソコンも壊しません。管理者さんの肖像画も毎日描いてあげます！","ENG":"I promise I won't forget to do any chores. I won't break the computer while playing. And I'll even draw your portrait every single day, Mr. Administrator!","TWN":"我不會忘記跑腿的事的。我也不會在玩的時候弄壞電腦。我每天都會給管理者先生畫肖像畫的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그러니까 한 번만…! 네에-?","JPN":"だから、一度だけ……！　ねえ～！","ENG":"So just this once...! Pleeeeease?","TWN":"就這一次嘛……！好不好？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"와아! 고마워요!","JPN":"わあ！　ありがとうございます！","ENG":"Wow! Thank you!","TWN":"哇，謝謝你！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"네…? 도장만 찍는다고 어른이 되는 건 아니라고요?","JPN":"えっ……？　ハンコを押すだけで大人になるわけではないんですか？","ENG":"What...? Just signing this doesn't make me an adult?","TWN":"嗯……？不是蓋個章就能成為大人喔？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"과, 관리자 씨! 그런 건 당연히 저도 알죠!","JPN":"か、管理者さん！　それは当然私もわかってますよ！","ENG":"M-Mr. Administrator! Of course, I know that!","TWN":"管，管理者先生！那種事我當然也知道！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"SURPRISE2"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그러니까, 그게… 인형 갖고 노는 시간이랑 만화 보는 시간을 더 줄이면… 되나?","JPN":"だから、ええっと……ぬいぐるみと遊ぶ時間と、マンガを読む時間を減らしたら……いいのかな？","ENG":"So, um... if I reduce the time I play with dolls and read comics... will that do it?","TWN":"所以，如果減少玩娃娃和看漫畫的時間……這樣可以嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"아, 그리고 무엇보다…!","JPN":"あ、それになにより……！","ENG":"Oh, and above all...!","TWN":"喔，還有最重要的……！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"동료의 믿음을 저버리지 않는 거. 그게 어른이라고 생각해요.","JPN":"仲間の信頼を裏切らない。それが大人だと思うんです。","ENG":"Never letting down the trust of your comrades. I think that's what being an adult means.","TWN":"不辜負同伴的信任。我認為這才是大人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"이 계약은 그 믿음을 얻기 위한 첫번째 걸음이고요.","JPN":"この契約はその信頼を得るための第一歩です。","ENG":"And this contract is the first step toward earning that trust.","TWN":"這份契約是贏得信任的第一步。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그러니까- 앞으로도 절 마음껏 믿어주세요! 관리자 씨!","JPN":"だからーこれからも私を思いきり信頼してください！　管理者さん！","ENG":"So, please continue to trust me wholeheartedly from now on! Mr. Administrator!","TWN":"所以，以後請儘管相信我吧！管理者先生！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};